+    fn sweep_capacity_pages(domain_pages: usize, percent: usize) -> usize {
+        let scaled = domain_pages.saturating_mul(percent);
+        let mut pages = scaled / 100;
+        if scaled % 100 != 0 {
+            pages = pages.saturating_add(1);
+        }
+        pages.max(1)
+    }
