+    fn format_percent(value: f64) -> String {
+        format!("{:.2}%", value * 100.0)
+    }
+
+    fn format_bar(value: f64) -> String {
+        let clamped = value.clamp(0.0, 1.0);
+        let width = (clamped * 20.0).round() as usize;
+        let count = width.max(1);
+        "#".repeat(count)
+    }
